BEGIN; CREATE OR REPLACE FUNCTION public.can_edit_delivery_plan() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT (public.is_admin() OR EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid() AND p.department = 'sales' AND COALESCE(p.is_active, false) = true AND COALESCE(p.is_approved, true) = true AND p.deleted_at IS NULL)); $$; GRANT EXECUTE ON FUNCTION public.can_edit_delivery_plan() TO authenticated; CREATE OR REPLACE FUNCTION public.save_delivery_plan_edits_v1(p_edits jsonb) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_user_id uuid := auth.uid(); v_now timestamptz := now(); v_item jsonb; v_plan_id uuid; v_existing public.delivery_plans%ROWTYPE; v_product public.products%ROWTYPE; v_product_id uuid; v_delivery_customer_id uuid; v_plan_date date; v_planned_qty numeric; v_new_note text; v_new_note_2 text; v_note_changed boolean; v_note_2_changed boolean; v_saved_count integer := 0; v_future_count integer := 0; v_relinked_count integer := 0; v_rows integer := 0; v_delivery_key uuid; v_existing_delivery_key uuid; v_customer_relinked boolean := false; BEGIN IF v_user_id IS NULL OR NOT public.can_edit_delivery_plan() THEN RAISE EXCEPTION 'Ban khong co quyen luu ke hoach giao hang.'; END IF; IF p_edits IS NULL OR jsonb_typeof(p_edits) <> 'array' THEN RAISE EXCEPTION 'Du lieu luu ke hoach khong hop le.'; END IF; IF jsonb_array_length(p_edits) = 0 THEN RETURN jsonb_build_object('saved', 0, 'future_notes_updated', 0, 'customer_relinked', 0); END IF; PERFORM set_config('app.skip_delivery_backlog_sync', 'on', true); FOR v_item IN SELECT * FROM jsonb_array_elements(p_edits) LOOP v_customer_relinked := false; v_existing_delivery_key := NULL; v_plan_id := NULLIF(v_item->>'id', '')::uuid; v_product_id := NULLIF(v_item->>'product_id', '')::uuid; v_delivery_customer_id := NULLIF(v_item->>'delivery_customer_id', '')::uuid; v_plan_date := NULLIF(v_item->>'plan_date', '')::date; v_planned_qty := COALESCE(NULLIF(v_item->>'planned_qty', '')::numeric, 0); v_new_note := v_item->>'note'; v_new_note_2 := v_item->>'note_2'; v_note_changed := COALESCE((v_item->>'note_changed')::boolean, false); v_note_2_changed := COALESCE((v_item->>'note_2_changed')::boolean, false); IF v_plan_id IS NULL OR v_product_id IS NULL OR v_plan_date IS NULL THEN RAISE EXCEPTION 'Dong ke hoach bi thieu thong tin bat buoc.'; END IF; IF v_planned_qty < 0 THEN RAISE EXCEPTION 'So luong ke hoach khong duoc am.'; END IF; SELECT * INTO v_product FROM public.products WHERE id = v_product_id AND deleted_at IS NULL; IF NOT FOUND THEN RAISE EXCEPTION 'Khong tim thay ma hang trong ke hoach.'; END IF; v_delivery_key := public.delivery_point_key(v_product.customer_id, v_delivery_customer_id); PERFORM pg_advisory_xact_lock(hashtextextended(v_product_id::text || '|' || v_plan_date::text || '|' || v_delivery_key::text, 20260523)); SELECT * INTO v_existing FROM public.delivery_plans dp WHERE dp.id = v_plan_id AND dp.deleted_at IS NULL FOR UPDATE; IF NOT FOUND THEN SELECT * INTO v_existing FROM public.delivery_plans dp WHERE dp.deleted_at IS NULL AND dp.plan_date = v_plan_date AND dp.product_id = v_product_id AND public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) = v_delivery_key FOR UPDATE; ELSE v_existing_delivery_key := public.delivery_point_key(v_existing.customer_id, v_existing.delivery_customer_id); IF v_existing.product_id <> v_product_id OR v_existing.plan_date <> v_plan_date THEN RAISE EXCEPTION 'Dong ke hoach khong khop voi du lieu dang luu.'; END IF; IF v_existing_delivery_key <> v_delivery_key THEN IF v_existing.delivery_customer_id IS NULL AND v_delivery_customer_id IS NULL AND v_existing.customer_id IS DISTINCT FROM v_product.customer_id AND COALESCE(v_existing.actual_qty, 0) = 0 AND COALESCE(v_existing.is_completed, false) = false THEN v_customer_relinked := true; ELSE RAISE EXCEPTION 'Dong ke hoach khong khop voi du lieu dang luu.'; END IF; END IF; END IF; IF v_existing.id IS NULL THEN INSERT INTO public.delivery_plans (id, plan_date, product_id, customer_id, delivery_customer_id, planned_qty, note, note_2, note_edited_at, note_2_edited_at, created_at, created_by, updated_at, updated_by) VALUES (v_plan_id, v_plan_date, v_product_id, v_product.customer_id, v_delivery_customer_id, v_planned_qty, v_new_note, v_new_note_2, CASE WHEN v_note_changed THEN v_now ELSE NULL END, CASE WHEN v_note_2_changed THEN v_now ELSE NULL END, v_now, v_user_id, v_now, v_user_id); ELSE UPDATE public.delivery_plans SET customer_id = CASE WHEN v_customer_relinked THEN v_product.customer_id ELSE customer_id END, planned_qty = v_planned_qty, note = v_new_note, note_2 = v_new_note_2, note_edited_at = CASE WHEN v_note_changed THEN v_now ELSE note_edited_at END, note_2_edited_at = CASE WHEN v_note_2_changed THEN v_now ELSE note_2_edited_at END, updated_at = v_now, updated_by = v_user_id WHERE id = v_existing.id; v_plan_id := v_existing.id; IF v_customer_relinked THEN v_relinked_count := v_relinked_count + 1; END IF; END IF; v_saved_count := v_saved_count + 1; IF v_note_changed THEN UPDATE public.delivery_plans dp SET note = v_new_note, note_edited_at = v_now, updated_at = v_now, updated_by = v_user_id WHERE dp.deleted_at IS NULL AND dp.product_id = v_product_id AND dp.plan_date > v_plan_date AND public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) = v_delivery_key AND COALESCE(dp.actual_qty, 0) = 0 AND COALESCE(dp.is_completed, false) = false AND (dp.note IS DISTINCT FROM v_new_note OR dp.note_edited_at IS DISTINCT FROM v_now); GET DIAGNOSTICS v_rows = ROW_COUNT; v_future_count := v_future_count + v_rows; END IF; IF v_note_2_changed THEN UPDATE public.delivery_plans dp SET note_2 = v_new_note_2, note_2_edited_at = v_now, updated_at = v_now, updated_by = v_user_id WHERE dp.deleted_at IS NULL AND dp.product_id = v_product_id AND dp.plan_date > v_plan_date AND public.delivery_point_key(dp.customer_id, dp.delivery_customer_id) = v_delivery_key AND COALESCE(dp.actual_qty, 0) = 0 AND COALESCE(dp.is_completed, false) = false AND (dp.note_2 IS DISTINCT FROM v_new_note_2 OR dp.note_2_edited_at IS DISTINCT FROM v_now); GET DIAGNOSTICS v_rows = ROW_COUNT; v_future_count := v_future_count + v_rows; END IF; END LOOP; PERFORM set_config('app.skip_delivery_backlog_sync', 'off', true); RETURN jsonb_build_object('saved', v_saved_count, 'future_notes_updated', v_future_count, 'customer_relinked', v_relinked_count); EXCEPTION WHEN OTHERS THEN PERFORM set_config('app.skip_delivery_backlog_sync', 'off', true); RAISE; END; $$; GRANT EXECUTE ON FUNCTION public.save_delivery_plan_edits_v1(jsonb) TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
